import { promises as fs } from "node:fs";
import path from "node:path";
import { COUNTS, SITE } from "@/lib/constants";
import { source } from "@/lib/source";

// Markdown-for-Agents target. middleware.ts rewrites requests carrying
// `Accept: text/markdown` for `/` and `/docs/*` here, so the same URL serves HTML
// to browsers and raw Markdown to agents. The raw .mdx files are bundled on Vercel
// via outputFileTracingIncludes in next.config.mjs.
// https://developers.cloudflare.com/fundamentals/reference/markdown-for-agents/
export const dynamic = "force-dynamic";

const MD_HEADERS = {
	"Content-Type": "text/markdown; charset=utf-8",
	"Cache-Control": "public, max-age=3600",
} as const;

function stripFrontmatter(raw: string): string {
	// Remove a leading YAML frontmatter block (--- ... ---) if present.
	const m = raw.match(/^---\n[\s\S]*?\n---\n?/);
	return m ? raw.slice(m[0].length) : raw;
}

function homepageMarkdown(): string {
	const pages = source.getPages();
	return [
		`# ${SITE.name}`,
		"",
		`> AI development toolkit for Claude Code — ${COUNTS.skills} skills, ${COUNTS.agents} agents, ${COUNTS.hooks} hooks.`,
		"",
		"## Documentation",
		"",
		...pages.map(
			(p) => `- [${p.data.title}](${p.url}): ${p.data.description ?? ""}`,
		),
		"",
	].join("\n");
}

export async function GET(
	_req: Request,
	{ params }: { params: Promise<{ slug?: string[] }> },
) {
	const { slug } = await params;

	// Homepage (empty slug) — synthesize a markdown index.
	if (!slug || slug.length === 0) {
		return new Response(homepageMarkdown(), { headers: MD_HEADERS });
	}

	const page = source.getPage(slug);
	if (!page) return new Response("Not found\n", { status: 404 });

	const rel = page.slugs.join("/");
	const candidates = [
		path.join(process.cwd(), "content/docs", `${rel}.mdx`),
		path.join(process.cwd(), "content/docs", rel, "index.mdx"),
	];

	for (const file of candidates) {
		try {
			const raw = await fs.readFile(file, "utf-8");
			const body = stripFrontmatter(raw).trim();
			const md = `# ${page.data.title}\n\n${page.data.description ?? ""}\n\n${body}\n`;
			return new Response(md, { headers: MD_HEADERS });
		} catch {
			// try next candidate
		}
	}

	// Source file unavailable — fall back to title + description so the request
	// still negotiates to markdown rather than 500-ing.
	const fallback = `# ${page.data.title}\n\n${page.data.description ?? ""}\n`;
	return new Response(fallback, { headers: MD_HEADERS });
}
